      "content": "const path = require('path');
const fs = require('fs');

const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');

function loadProblemsData() {
  try {
    const raw = fs.readFileSync(problemsDataPath, 'utf8');
    return JSON.parse(raw);
  } catch (e) {
    return [];
  }
}

class ProblemsService {
  static getProblemById(problemId) {
    const problems = loadProblemsData();
    return problems.find(p => String(p.id) === String(problemId));
  }

  static getProblemDetails(problemId) {
    const problem = this.getProblemById(problemId);
    if (!problem) {
      return null;
    }

    // Aggregate component statistics
    // Each problem has components array with language, status, points
    const components = problem.components || [];

    const languageCounts = {};
    const statusCounts = {};
    let maxPoints = 0;

    components.forEach(c => {
      if (c.language) {
        languageCounts[c.language] = (languageCounts[c.language] || 0) + 1;
      }
      if (c.status) {
        statusCounts[c.status] = (statusCounts[c.status] || 0) + 1;
      }
      if (typeof c.points === 'number' && c.points > maxPoints) {
        maxPoints = c.points;
      }
    });

    return {
      id: problem.id,
      name: problem.name,
      description: problem.description,
      components,
      componentStats: {
        languageCounts,
        statusCounts,
        maxPoints
      }
    };
  }
}

module.exports = ProblemsService;
